import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.parser.Parser;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.io.ByteArrayInputStream;
import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

import static org.junit.jupiter.api.Assertions.*;
public class Jsoup_parse_1_Test {

    @Test
    @DisplayName("parse(html non-empty) uses default parser and empty baseUri")
    public void test_TC11() {
        String html = "<span>X</span>";
        Document doc = Jsoup.parse(html);
        assertEquals("X", doc.select("span").text(), "Content should be parsed by default HTML parser");
        assertEquals("", doc.baseUri(), "Default baseUri should be empty string");
    }

    @Test
    @DisplayName("parse(html non-empty, Parser) uses provided parser and empty baseUri")
    public void test_TC12() {
        String html = "<node/>";
        Parser parser = Parser.xmlParser();
        Document doc = Jsoup.parse(html, parser);
        assertEquals(1, doc.select("node").size(), "XML parser should recognize self-closing node element");
        assertEquals("", doc.baseUri(), "BaseUri should remain empty when not provided");
    }

    @Test
    @DisplayName("parse(html null) throws IllegalArgumentException in single-arg overload")
    public void test_TC13() {
        String html = null;
        assertThrows(IllegalArgumentException.class, () -> Jsoup.parse(html),
                "Parsing null HTML should throw IllegalArgumentException");
    }

    @Test
    @DisplayName("parse(File file exists) determines charset from BOM/meta and uses file absolute path")
    public void test_TC14() throws IOException {
        File tmp = File.createTempFile("p14", ".html");
        tmp.deleteOnExit();
        String content = "<p>Z</p>";
        Files.write(tmp.toPath(), content.getBytes(StandardCharsets.UTF_8));
        Document doc = Jsoup.parse(tmp);
        assertEquals("Z", doc.select("p").text(), "File-based parse should read element text correctly");
        assertEquals(tmp.getAbsolutePath(), doc.baseUri(), "BaseUri should be the file's absolute path");
    }

    @Test
    @DisplayName("parse(File,charset,baseUri,Parser) uses custom parser and explicit baseUri")
    public void test_TC15() throws IOException {
        File tmp = File.createTempFile("p15", ".html");
        tmp.deleteOnExit();
        String content = "<t>Y</t>";
        Files.write(tmp.toPath(), content.getBytes(StandardCharsets.UTF_8));
        String cs = "UTF-8";
        String base = "http://base/";
        Parser parser = Parser.xmlParser();
        Document doc = Jsoup.parse(tmp, cs, base, parser);
        assertEquals("Y", doc.select("t").text(), "Custom parser should recognize element t");
        assertEquals(base, doc.baseUri(), "BaseUri should match provided value");
    }

    @Test
    @DisplayName("parse(Path,charset,baseUri) uses Path overload and custom charset and URI")
    public void test_TC16() throws IOException {
        Path path = Files.createTempFile("p16", ".html");
        path.toFile().deleteOnExit();
        String html = "<div>P</div>";
        Files.write(path, html.getBytes(StandardCharsets.UTF_8));
        String cs = "UTF-8";
        String base = "https://uri/";
        Document doc = Jsoup.parse(path, cs, base);
        assertEquals("P", doc.select("div").text(), "Path-based parse should read div content");
        assertEquals(base, doc.baseUri(), "BaseUri should match provided URI");
    }

    @Test
    @DisplayName("parse(Path,Parser overload) throws IOException for non-existent file")
    public void test_TC17() {
        Path path = Paths.get("does-not-exist.html");
        assertThrows(IOException.class, () -> Jsoup.parse(path),
                "Parsing non-existent path should throw IOException");
    }

    @Test
    @DisplayName("parse(InputStream,charset,baseUri,Parser) closes stream and uses parser")
    public void test_TC18() throws IOException {
        byte[] data = "<em>E</em>".getBytes(StandardCharsets.UTF_8);
        InputStream in = new ByteArrayInputStream(data);
        String cs = "UTF-8";
        String base = "http://u/";
        Parser parser = Parser.xmlParser();
        Document doc = Jsoup.parse(in, cs, base, parser);
        assertEquals("E", doc.select("em").text(), "Stream-based parse should process element em");
        assertEquals(base, doc.baseUri(), "BaseUri should match provided URI");
        // ensure stream is closed: reading further should yield -1
        assertEquals(-1, in.read(), "InputStream should be closed after parsing");
    }
}
- Error Log Message: 

2) **What to Produce**
- Output a single JSON object containing an array named `"ErrorGuides"`.
- Each element of `"ErrorGuides"` MUST have exactly these keys:
  - `"ErrorSpot"`: A precise pointer to the error location (e.g., method name, file path + line number, or `"import section"`). If it is an import error, specify `"import section"` and the file.
  - `"ErrorCause"`: A concise English description of the root cause (why it failed).
  - `"ErrorGuide"`: A pseudocode-style, step-by-step fix guide in English.
  - `"Before"`: The minimal code fragment (or signature) that is wrong.
  - `"After"`: The corrected minimal code fragment (or signature) that should replace the `"Before"`.
- Only report issues that are evidenced by the provided error log. Do not invent additional problems.
- If multiple errors exist, list them in the order they appear in the log.

3) **Constraints**
- Do NOT change the number of test scenarios (this prompt does not ask you to output fixed tests).
- Keep fixes minimal and focused strictly on the error causes shown in the log.
- If the error references a missing/invalid constructor or generic type inference failure, show the corrected constructor/generics explicitly in `"After"`.
- If the error references class/file name mismatch, `"ErrorSpot"` must include both the public class name and the filename, and `"Before"`/`"After"` must reflect the correct pairing.
- If reflection access or import is the issue, set fields accessible and ensure imports are correct, but only if such errors are indicated in the log.
- Avoid mocks/abstractions unless the log directly points to them.

4) **Style**
- All explanations (`"ErrorCause"` and `"ErrorGuide"`) should be in **English**.
- Keep `"Before"`/`"After"` as short, minimal code blocks or single-line signatures where possible.
- If line numbers are present in the log, include them in `"ErrorSpot"` (e.g., `"…Test.java:123:45"`).

[Error Categories to Handle]
You must analyze and report all errors from the following categories:
  1) Type: Syntax / Compile Error
  Description: Missing import, invalid class, wrong method signature, incompatible types
  Examples: “cannot find symbol”, “missing return statement”, “incompatible types”

  2) Type: Runtime Error
  Description: Exception occurring during test execution
  Examples: “NullPointerException”, “IndexOutOfBoundsException”, “IllegalArgumentException”


[Rules for Each Error Type]
  1) Compile-Time Errors:
  Identify incorrect syntax, type, import, or constructor.
  Include file and class name if mismatched.
  Keep “Before” and “After” minimal and focused.

  2) Runtime Errors:
  Specify which statement threw the exception.
  Suggest fixes such as null checks, bounds checks, or proper initialization.


[Emphasis/Request]
- Minimize changes; focus on compilability/run-ability per the error log.
- Never summarize or remove scenarios; this prompt is ONLY for producing Error Guides.
- Ensure steps are practical and do not introduce infinite loops or unrelated edits.

[Output Format]
Return ONLY one JSON object, enclosed in triple backticks as `"json"`. The schema MUST be:

```json
{
  "ErrorGuides": [
    {
      "ErrorSpot": "<file path or class#method or 'import section'>",
      "ErrorCause": "<short and clear explanation of the cause>",
      "ErrorGuide": "<pseudocode-style step-by-step fix guide>",
      "Before": "<minimal code snippet that is wrong>",
      "After": "<corrected minimal code snippet>"
    }
    // ... more errors in log order
  ]
}

[SUMMARY]
Output strictly JSON (no extra text or markdown).
Focus only on real, logged issues.
Ensure minimal, safe, and realistic fixes.
Avoid any fix that could introduce infinite loops or unbounded execution.
Goal: Produce a clean, precise, developer-ready Error Guide JSON.
